/**
 * MMS Fleet Service
 *
 * Core domain service for fleet asset management.
 * Provides CRUD operations for depots, fleets, trains, routes, and tracks.
 * Manages train lifecycle states and mileage tracking.
 *
 * Business rules:
 * - Train fitness transitions: FIT <-> RESTRICTED <-> GROUNDED
 * - Mileage accumulation is additive (never decreases except for corrections)
 * - Fleet mileage balancing: target = fleet average, variance = current - target
 * - Active entities can be deactivated but not deleted (audit compliance)
 *
 * @see specs/003-database-schema.md Section 3.2 (Core Fleet Domain)
 */

import { eq, and, inArray, sql, desc, asc, count, avg, sum, type SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  depots,
  fleets,
  trains,
  routes,
  tracks,
  type Depot,
  type NewDepot,
  type Fleet,
  type NewFleet,
  type Train,
  type NewTrain,
  type Route,
  type NewRoute,
  type Track,
  type NewTrack,
} from '../lib/db/schema';
import {
  NotFoundError,
  TrainNotFoundError,
  ValidationError,
  DuplicateError,
  BusinessRuleError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Valid fitness status transitions */
type FitnessStatus = 'FIT' | 'RESTRICTED' | 'GROUNDED';

/** Query filters for listing trains */
export interface TrainListFilters {
  fleetId?: string;
  depotId?: string;
  fitnessStatus?: FitnessStatus | FitnessStatus[];
  active?: boolean;
  trainNumbers?: string[];
}

/** Query filters for listing fleets */
export interface FleetListFilters {
  baseDepotId?: string;
  manufacturer?: string;
  active?: boolean;
}

/** Pagination options */
export interface PaginationOptions {
  page?: number;
  pageSize?: number;
  sortBy?: string;
  sortOrder?: 'asc' | 'desc';
}

/** Paginated result */
export interface PaginatedResult<T> {
  data: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

/** Fleet statistics */
export interface FleetStatistics {
  fleetId: string;
  fleetCode: string;
  totalTrains: number;
  activeTrains: number;
  fitTrains: number;
  restrictedTrains: number;
  groundedTrains: number;
  totalMileageKm: number;
  averageMileageKm: number;
  minMileageKm: number;
  maxMileageKm: number;
  mileageStdDevKm: number;
}

/** Train with fleet details */
export interface TrainWithFleet extends Train {
  fleet: Fleet | null;
  currentDepot: Depot | null;
  homeDepot: Depot | null;
}

/** Fitness status change request */
export interface FitnessStatusChangeRequest {
  trainId: string;
  newStatus: FitnessStatus;
  notes?: string;
  changedBy?: string;
}

/** Mileage update request */
export interface MileageUpdateRequest {
  trainId: string;
  newMileageKm: number;
  source?: string;
}

// =============================================================================
// Fleet Service
// =============================================================================

export class FleetService extends BaseService {
  constructor() {
    super({ name: 'fleet-service', version: '1.0.0' });
  }

  // ===========================================================================
  // Depot Operations
  // ===========================================================================

  async getDepotById(id: string): Promise<Depot> {
    return this.traced('getDepotById', async (span) => {
      span.setAttribute(MmsAttributes.DEPOT_ID, id);

      const result = await this.db.query.depots.findFirst({
        where: eq(depots.id, id),
      });

      if (!result) {
        throw new NotFoundError(`Depot not found: ${id}`, {
          entityType: 'depot',
          entityId: id,
        });
      }

      return result;

import './App.css'

function App() {
  return (
    <div className="mms-app">
      <h1>MMS Demo Application</h1>
      <p>Metro Fleet Mileage Management System</p>
      <p className="mms-status">Ready for development</p>
    </div>
  )
}

export default App

/**
 * MMS Database Connection
 *
 * PostgreSQL connection pool using postgres.js driver with Drizzle ORM.
 * Configured for production use with health checks and connection limits.
 *
 * Environment Variables:
 * - DATABASE_URL: PostgreSQL connection string (required)
 * - DATABASE_MAX_CONNECTIONS: Max pool size (default: 20)
 * - DATABASE_SSL: Enable SSL (default: true in production)
 *
 * @see specs/008-operations-deployment.md for production configuration
 */

import { drizzle } from 'drizzle-orm/postgres-js';
import postgres from 'postgres';
import * as schema from './schema';

/**
 * Database configuration from environment
 */
const config = {
  url: process.env['DATABASE_URL'] ?? 'postgresql://mms:mms@localhost:5432/mms_dev',
  maxConnections: parseInt(process.env['DATABASE_MAX_CONNECTIONS'] ?? '20', 10),
  ssl: process.env['DATABASE_SSL'] === 'true' || process.env['NODE_ENV'] === 'production',
  idleTimeout: 20, // seconds
  connectTimeout: 10, // seconds
};

/**
 * PostgreSQL connection pool
 *
 * Using postgres.js for:
 * - Native ESM support
 * - Excellent TypeScript support
 * - Prepared statements
 * - Connection pooling
 */
export const sql = postgres(config.url, {
  max: config.maxConnections,
  idle_timeout: config.idleTimeout,
  connect_timeout: config.connectTimeout,
  ssl: config.ssl ? { rejectUnauthorized: false } : false,
  // Prepare statements for better performance
  prepare: true,
  // Transform column names from snake_case to camelCase
  // Note: Drizzle handles this, so we keep original names
  transform: {
    undefined: null,
  },
  // Connection event handlers for logging/monitoring
  onnotice: () => {
    // Suppress notices in production
  },
});

/**
 * Drizzle ORM instance
 *
 * Provides type-safe query builder with full schema awareness.
 * All queries automatically use the connection pool.
 */
export const db = drizzle(sql, {
  schema,
  logger: process.env['NODE_ENV'] === 'development',
});

/**
 * Database health check
 *
 * Use this for liveness/readiness probes in Kubernetes.
 * Returns true if the database is reachable and responsive.
 */
export async function checkDatabaseHealth(): Promise<boolean> {
  try {
    const result = await sql`SELECT 1 as health`;
    return result.length === 1 && result[0]?.health === 1;
  } catch {
    return false;
  }
}

/**
 * Graceful shutdown
 *
 * Close all database connections gracefully.
 * Call this during application shutdown.
 */
export async function closeDatabaseConnection(): Promise<void> {
  await sql.end();
}

/**
 * Database transaction helper
 *
 * Executes a function within a database transaction.
 * Automatically commits on success or rolls back on error.
 *
 * @example
 * const result = await withTransaction(async (tx) => {
 *   await tx.insert(trains).values({ ... });
 *   await tx.insert(pmSchedule).values({ ... });
 *   return { success: true };
 * });
 */
export type Transaction = Parameters<Parameters<typeof db.transaction>[0]>[0];

export async function withTransaction<T>(
  fn: (tx: Transaction) => Promise<T>
): Promise<T> {
  return db.transaction(async (tx) => fn(tx));
}

// Export types for use in services
export type Database = typeof db;

/**
 * MMS Logging Configuration
 *
 * Structured logging with Pino for consistent log format across all services.
 * Features:
 * - JSON format in production
 * - Pretty print in development
 * - Sensitive field redaction
 * - Request ID propagation
 * - OpenTelemetry trace context
 *
 * @see specs/004-backend-specification.md Section 4.14
 */

import pino, { type Logger, type LoggerOptions } from 'pino';

const isDevelopment = process.env['NODE_ENV'] === 'development';

/**
 * Fields to redact from logs (prevents PII/secrets leakage)
 */
const REDACT_PATHS = [
  'password',
  'passwordHash',
  'password_hash',
  'token',
  'accessToken',
  'refreshToken',
  'apiKey',
  'api_key',
  'authorization',
  'cookie',
  'creditCard',
  'ssn',
  '*.password',
  '*.token',
  '*.apiKey',
  'req.headers.authorization',
  'req.headers.cookie',
];

/**
 * Base logger configuration
 */
const baseOptions: LoggerOptions = {
  level: process.env['LOG_LEVEL'] ?? (isDevelopment ? 'debug' : 'info'),
  redact: {
    paths: REDACT_PATHS,
    censor: '[REDACTED]',
  },
  formatters: {
    level: (label) => ({ level: label }),
    bindings: (bindings) => ({
      pid: bindings.pid,
      host: bindings.hostname,
      service: process.env['SERVICE_NAME'] ?? 'mms',
    }),
  },
  timestamp: pino.stdTimeFunctions.isoTime,
  base: {
    env: process.env['NODE_ENV'] ?? 'development',
  },
};

/**
 * Development transport (pretty print)
 */
const developmentTransport = {
  target: 'pino-pretty',
  options: {
    colorize: true,
    translateTime: 'HH:MM:ss.l',
    ignore: 'pid,hostname',
    singleLine: false,
  },
};

/**
 * Create the root logger instance
 */
function createLogger(): Logger {
  if (isDevelopment) {
    return pino({
      ...baseOptions,
      transport: developmentTransport,
    });
  }

  return pino(baseOptions);
}

/**
 * Root logger instance
 */
export const logger = createLogger();

/**
 * Create a child logger with additional context
 * Use for service-specific or request-specific logging
 */

