/**
 * MMS Error Classes
 *
 * Typed error classes for consistent error handling across the application.
 * Each error includes a code for client-side handling and logging.
 *
 * Error code format: CATEGORY_NNN
 * - FILE_001-099: File/CSV processing errors
 * - ROW_001-099: Row/record validation errors
 * - SYS_001-099: System/infrastructure errors
 * - BUS_001-099: Business logic errors
 * - AUTH_001-099: Authentication/authorization errors
 * - EXT_001-099: External system errors (Maximo, etc.)
 *
 * @see specs/004-backend-specification.md Section 4.15
 */

/**
 * Base error class for all MMS errors
 */
export abstract class MmsError extends Error {
  abstract readonly code: string;
  abstract readonly statusCode: number;
  readonly isOperational: boolean = true;
  readonly timestamp: Date = new Date();
  readonly context?: Record<string, unknown>;

  constructor(message: string, context?: Record<string, unknown>) {
    super(message);
    this.name = this.constructor.name;
    this.context = context;
    Error.captureStackTrace(this, this.constructor);
  }

  toJSON() {
    return {
      name: this.name,
      code: this.code,
      message: this.message,
      statusCode: this.statusCode,
      timestamp: this.timestamp.toISOString(),
      ...(this.context && { context: this.context }),
    };
  }
}

// =============================================================================
// Validation Errors (400)
// =============================================================================

export class ValidationError extends MmsError {
  readonly code = 'BUS_001';
  readonly statusCode = 400;
  readonly field?: string;
  readonly errors?: Array<{ field: string; message: string }>;

  constructor(
    message: string,
    options?: {
      field?: string;
      errors?: Array<{ field: string; message: string }>;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.field = options?.field;
    this.errors = options?.errors;
  }
}

export class CsvValidationError extends MmsError {
  readonly code = 'FILE_001';
  readonly statusCode = 400;
  readonly row?: number;
  readonly column?: string;

  constructor(
    message: string,
    options?: {
      row?: number;
      column?: string;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.row = options?.row;
    this.column = options?.column;
  }
}

export class RowValidationError extends MmsError {
  readonly code = 'ROW_001';
  readonly statusCode = 400;
  readonly row: number;
  readonly column?: string;
  readonly value?: unknown;

  constructor(
    message: string,
    row: number,
    options?: {
      column?: string;
      value?: unknown;
      context?: Record<string, unknown>;
    }
  ) {
    super(message, options?.context);
    this.row = row;
    this.column = options?.column;
    this.value = options?.value;
  }
}

export class FileError extends MmsError {
  readonly code = 'FILE_002';
  readonly statusCode = 400;
  readonly filePath?: string;
  readonly operation?: string;

  constructor(

/**
 * MMS Prometheus Metrics
 *
 * Application metrics for monitoring and alerting.
 * Exposed via /metrics endpoint for Prometheus scraping.
 *
 * Metric types:
 * - Counter: Monotonically increasing values (requests, errors)
 * - Gauge: Point-in-time values (active jobs, queue depth)
 * - Histogram: Distribution of values (request duration, solve time)
 *
 * @see specs/004-backend-specification.md Section 4.14
 */

import { Registry, Counter, Gauge, Histogram, collectDefaultMetrics } from 'prom-client';

// =============================================================================
// Registry Setup
// =============================================================================

export const registry = new Registry();

// Add default Node.js metrics (CPU, memory, event loop, etc.)
collectDefaultMetrics({
  register: registry,
  prefix: 'mms_',
});

// =============================================================================
// HTTP Metrics
// =============================================================================

export const httpRequestsTotal = new Counter({
  name: 'mms_http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'path', 'status'] as const,
  registers: [registry],
});

export const httpRequestDuration = new Histogram({
  name: 'mms_http_request_duration_seconds',
  help: 'HTTP request duration in seconds',
  labelNames: ['method', 'path', 'status'] as const,
  buckets: [0.01, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10],
  registers: [registry],
});

export const httpRequestsInFlight = new Gauge({
  name: 'mms_http_requests_in_flight',
  help: 'Number of HTTP requests currently being processed',
  labelNames: ['method'] as const,
  registers: [registry],
});

// =============================================================================
// PM Scheduling Metrics
// =============================================================================

export const pmScheduledTotal = new Counter({
  name: 'mms_pm_scheduled_total',
  help: 'Total number of PM events scheduled',
  labelNames: ['pm_code', 'fleet_id', 'status'] as const,
  registers: [registry],
});

export const pmComplianceWindowDays = new Histogram({
  name: 'mms_pm_compliance_window_days',
  help: 'Days between PM scheduling and compliance window end',
  labelNames: ['pm_code'] as const,
  buckets: [-14, -7, 0, 7, 14, 30, 60, 90],
  registers: [registry],
});

export const pmDeferredTotal = new Counter({
  name: 'mms_pm_deferred_total',
  help: 'Total number of PM events deferred',
  labelNames: ['pm_code', 'reason'] as const,
  registers: [registry],
});

// =============================================================================
// Optimizer Metrics
// =============================================================================

export const optimizerSolveSeconds = new Histogram({
  name: 'mms_optimizer_solve_seconds',
  help: 'Optimizer solve time in seconds',
  labelNames: ['solver_type', 'status'] as const,
  buckets: [0.1, 0.5, 1, 5, 10, 30, 60, 120],
  registers: [registry],
});

export const optimizerRunsTotal = new Counter({
  name: 'mms_optimizer_runs_total',
  help: 'Total number of optimizer runs',
  labelNames: ['solver_type', 'status'] as const,
  registers: [registry],
});

